head.script:
var MSG_LO_ERR_001 = "사용자ID를 입력하세요.";
var MSG_LO_ERR_002 = "사용자명을 입력하세요.";
var MSG_LO_ERR_003 = "휴대폰번호를 입력하세요.";
var MSG_LO_ERR_004 = "인증번호 전송을 진행하세요.";
var MSG_LO_ERR_005 = "인증번호를 입력하세요.";
var MSG_LO_ERR_006 = "휴대폰전화번호를 정확하게 입력해 주십시오.";

scwin.vAuthNoYn = "N";
// scwin.params = $c.data.getParameter();

scwin.onpageload = function () {
    scwin.params = $p.getParameter("rowObj");
    scwin.vType = scwin.params["type"]; // 계정잠금해제 (1) / 비밀번호초기화 (2)
    scwin.vAuthNoYn = "N";
    scwin.isAuthTimeoutAlertShown = false;   // [추가] 시간초과 팝업 1회 제한
    scwin.isTimerExpired = false; 

    scwin.toDay = WebSquare.date.getCurrentServerDate()
    scwin.day = WebSquare.date.dateAdd(scwin.toDay, 1)
};

// asis tobe 타이틀 상이할 경우 변경하는 함수.
scwin.popTitleCh = function () {
    if (scwin.params.type == "1") {
        $c.data.setPopupTitle("계정잠금해제");
    } else {
        $c.data.setPopupTitle("비밀번호초기화");
    }
};

scwin.f_ReqFieldChk = async function () {
    //필수입력항목 체크
    if (txt_userId.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_LO_ERR_001);
        return false;
    }

    if (txt_userNm.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_LO_ERR_002);
        return false;
    }

    if (txt_userMpNo.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_LO_ERR_003);
        return false;
    } else {
        var vTelNo = txt_userMpNo.getValue();
        var regExp = /^(01[016789]{1}|02|0[3-9]{1}[0-9]{1})-?[0-9]{3,4}-?[0-9]{4}$/;

        if (!regExp.test(vTelNo)) {
            await $c.gus.cfAlertMsg(MSG_LO_ERR_006);
            return;
        };
    }
    return true;
}

// 사용자 정보 확인
scwin.f_checkUserInfo = async function () {
    let chkVal = await scwin.f_ReqFieldChk();
    if (chkVal) {
        ds_user.set("userId", txt_userId.getValue());
        ds_user.set("userNm", txt_userNm.getValue());
        ds_user.set("userMpNo", txt_userMpNo.getValue());
        ds_user.set("chk", scwin.vType);
        $c.sbm.execute(sbm_retrieveUser); // tr_retrieveUser.post();
    }
}

// 인증번호 전송
scwin.f_smsSend = function () {
    $c.sbm.execute(sbm_saveAuthNo); // tr_saveAuthNo.post();
}

// 인증번호 확인
scwin.f_checkAuth = function () {
    if (scwin.vAuthNoYn == "N") {
        $c.gus.cfAlertMsg(MSG_LO_ERR_004);
        return false;
    }

    if (txt_autnNo.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_LO_ERR_005);
        return false;
    }
    ds_confirm.set("authNo", txt_autnNo.getValue());
    ds_confirm.set("rcvNo", txt_userMpNo.getValue());
    ds_confirm.set("rcvNo2", txt_userMpNo.getValue());

    $c.sbm.execute(sbm_retrieveAuthNo); // tr_retrieveAuthNo.post();
}

scwin.now = new Date();
scwin.minute = scwin.now.getMinutes().toString();
scwin.second = scwin.now.getSeconds().toString();
scwin.minute = 5;
scwin.second = 00;
scwin.end = 0;

scwin.f_TimerCount = async function () {

    // 시간초과 후에는 뒤늦게 들어온 타이머도 전부 중지
    if (scwin.isTimerExpired) {
        txt_min.setValue("00");
        txt_secs.setValue("00");
        return;
    }

    if (scwin.second == 00) {
        scwin.minute = scwin.minute - 1;
        scwin.second = 59;
    } else {
        scwin.second = scwin.second - 1;
    }

    if ((scwin.minute < 0) && (scwin.end == 0)) {

        // 만료 상태로 전환
        scwin.isTimerExpired = true;

        // 화면은 00:00으로 고정
        scwin.minute = 0;
        scwin.second = 0;
        txt_min.setValue("00");
        txt_secs.setValue("00");

        if (!scwin.isAuthTimeoutAlertShown) {
            scwin.isAuthTimeoutAlertShown = true;   // 먼저 잠금
            await $c.win.alert("인증시간이 지났습니다.");
            window.close();
        }
        scwin.vAuthNoYn = "N";
        scwin.minute = 5;
        scwin.second = 00;
        return;
    }

    txt_min.setValue(0 + scwin.minute.toString());
    if (scwin.second < 10) {
        txt_secs.setValue(0 + scwin.second.toString());
    } else {
        txt_secs.setValue(scwin.second);
    }

    setTimeout(function () {
        scwin.f_TimerCount();
    }, 1000);
}


// 사용자 정보 변경
scwin.f_userChange = function () {
    $c.sbm.execute(sbm_saveUser);  // tr_saveUser.post();
}

//숫자 입력 체크
scwin.f_onlyNum = function (e) {
    var key = e.keyCode;
    if (!(key == 8 ||
        key == 9 ||
        key == 13 ||
        key == 46 ||
        key == 144 || (key >= 48 && key <= 57) ||
        key == 110 ||
        key == 190)) {

        $c.win.alert('숫자만 입력 가능합니다');
        e.returnValue = false;
    }
}

// <!-- 사용자확인 TR -->
// for=tr_retrieveUser event=OnSuccess()
scwin.sbm_retrieveUser_submitdone = function (e) {
    var vExistYn = ds_userResult.getCellData(0, "useYn");
    if ((scwin.vType == "1" && vExistYn == "0") || (scwin.vType == "2" && vExistYn == "1")) {
        scwin.f_smsSend();
        scwin.f_TimerCount();
    }
};

scwin.sbm_saveAuthNo_submit = function (e) {
    ds_condition.set("userId", txt_userId.getValue())
    ds_condition.set("userNm", txt_userNm.getValue())
    ds_condition.set("userMpNo", txt_userMpNo.getValue())
    ds_condition.set("rcvNo", txt_userMpNo.getValue())
};

// <!-- 인증번호전송 TR -->
// for=tr_saveAuthNo event=OnSuccess()
scwin.sbm_saveAuthNo_submitdone = function (e) {
    scwin.vAuthNoYn = "Y";
    scwin.isAuthTimeoutAlertShown = false;   // [추가] 시간초과 팝업 1회 제한
    scwin.isTimerExpired = false;   // [추가] 새 인증전송 시 다시 타이머 동작 허용
};

// for=tr_retrieveAuthNo event=OnSuccess()
scwin.sbm_retrieveAuthNo_submitdone = function (e) {
    if (ds_result.getCellData(0, "authNo") != "") {
        scwin.f_userChange();
    } else {
        $c.win.alert("유효하지 않은 인증번호입니다.");
        return;
    }
};

scwin.sbm_saveUser_submit = function (e) { };

// <!-- 사용자변경 TR -->
// for=tr_saveUser event=OnSuccess()
scwin.sbm_saveUser_submitdone = async function (e) {
    if (scwin.vType == "1") {
        var blockReason = ds_userResult.getCellData(0, "blockReason");
        if (blockReason == "D") {
            var msg = "사용자 아이디(" + ds_user.get("userId") + ")에 대해 비밀번호 만기 해제되었습니다.\n\n"
                + "아래 조치사항을 진행하시기 바랍니다.\n"
                + "-------------------------------------------------------------------------\n"
                + "1. DEBIS 로그인 후 우측 상단의 환경설정에서 비밀번호를 변경해 주시기 바랍니다. \n"
                + "2. 비밀번호 미 변경시 내일("
                + scwin.day.substring(4, 6) + "/" + scwin.day.substring(6, 8)
                + ") 다시 비밀번호 만기로 ID가 잠기게 됩니다.\n"
                + "-------------------------------------------------------------------------"
                ;
            await $c.win.alert(msg);
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_INF_014, ["계정잠금해제"]);	// @을(를)성공적으로 적용하였습니다
        }

    } else if (scwin.vType == "2") {
        var msg = "사용자 아이디(" + ds_user.get("userId") + ") 비밀번호 초기화 완료되었습니다.\n\n"
            + "초기화된 임시 비밀번호: a" + ds_user.get("userId");
        await $c.win.alert(msg);
    }
    window.close();
};

// 닫기 버튼 클릭 이벤트
scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};
